    state.deleted.concat(arr(remote.deleted)).forEach(function(d){if(d&&d.id&&(!deleted[d.id]||deleted[d.id]<d.ts))deleted[d.id]=d.ts;});
    state.rooms.forEach(function(r){map[r.id]=r;});remote.rooms.forEach(function(rr){rr=normalizeRoom(rr);var l=map[rr.id];if(!l||(rr.updatedAt||0)>(l.updatedAt||0))map[rr.id]=rr;});
    state.rooms=Object.keys(map).map(function(id){return map[id];}).filter(function(r){return !(deleted[r.id]&&deleted[r.id]>=r.updatedAt);});
    state.deleted=Object.keys(deleted).map(function(id){return{id:id,ts:deleted[id]};});state.updatedAt=Math.max(state.updatedAt||0,remote.updatedAt||0);saveLocal();
