  function pullCloud(){if(!ghReady()||navigator.onLine===false){setSync("local");return;}setSync("busy");fetch(ghUrl(),{headers:ghHeaders()}).then(function(r){if(r.status===404)return null;if(!r.ok)throw 0;return r.json();}).then(function(j){if(!j){setSync("local");return;}cloudSha=j.sha;mergeCloud(JSON.parse(b64d(j.content)));setSync("ok");if(!view.hidden)currentRoomId?renderRoom():renderMain();}).catch(function(){setSync("err");});}
