  function analysisSection(r){var total=arr(r.analysis.duplicates).length+arr(r.analysis.conflicts).length+arr(r.analysis.keypoints).length+arr(r.analysis.needsReview).length;if(!total)return"";var blocks=[{key:"duplicates",title:"중복 통합",emo:"🔗"},{key:"conflicts",title:"의견 충돌",emo:"◉"},{key:"keypoints",title:"핵심 추출",emo:"#"},{key:"needsReview",title:"확인 필요",emo:"?"}];return '<div class="st-section"><div class="st-section-head"><div><h2 class="st-section-title">AI 검토 메모</h2><p class="st-section-note">제품 카드 밖에서 따로 확인할 판단만 모읍니다.</p></div></div><div class="st-analysis-grid">'+blocks.map(function(b){var items=arr(r.analysis[b.key]).filter(function(x){return !onlyChanged||changed(x);});return'<section class="st-card st-analysis"><div class="st-analysis-head"><h3>'+b.emo+' '+b.title+'</h3><span>'+items.length+'개</span></div>'+(items.length?items.map(function(x){return insightRow(x,b.key);}).join(""):'<div class="st-insight"><p>표시할 내용이 없습니다.</p></div>')+'</section>';}).join("")+'</div></div>';}
