  function taxonomyEditModal(r){
    var entries=roomProductTaxonomy(r).map(function(t){return{original:t,name:t};}),m=modal('<h3>분류 태그 편집</h3><p class="st-modal-desc">이 방에서 실제로 사용할 분류만 남기고 순서를 정하세요.</p><div class="st-taxonomy-list" id="stTaxonomyList"></div><div class="st-taxonomy-tools"><button class="st-btn" data-tax-add>＋ 새 분류</button><button class="st-btn" data-tax-reset>기본 복원</button></div><div class="st-modal-actions"><button class="st-btn" data-close>취소</button><button class="st-btn primary" data-save>저장</button></div>'),list=m.querySelector("#stTaxonomyList");
    function sync(){list.querySelectorAll("[data-tax-name]").forEach(function(input,i){if(entries[i])entries[i].name=input.value;});}
    function draw(){list.innerHTML=entries.length?entries.map(function(e,i){return'<div class="st-taxonomy-row"><input class="st-input" data-tax-name value="'+esc(e.name)+'" aria-label="분류 이름"><div class="st-taxonomy-row-actions"><button data-tax-up="'+i+'" '+(i===0?'disabled':'')+' title="위로 이동">↑</button><button data-tax-down="'+i+'" '+(i===entries.length-1?'disabled':'')+' title="아래로 이동">↓</button><button data-tax-delete="'+i+'" title="분류 삭제">×</button></div></div>';}).join(""):'<div class="st-note">아직 상단 분류가 없어요. 새 분류를 추가하거나 제품 카드의 회색 태그를 눌러 올릴 수 있어요.</div>';list.querySelectorAll("[data-tax-up],[data-tax-down]").forEach(function(b){b.onclick=function(){sync();var i=Number(b.dataset.taxUp!=null?b.dataset.taxUp:b.dataset.taxDown),to=i+(b.dataset.taxUp!=null?-1:1);if(to<0||to>=entries.length)return;var x=entries.splice(i,1)[0];entries.splice(to,0,x);draw();};});list.querySelectorAll("[data-tax-delete]").forEach(function(b){b.onclick=function(){sync();entries.splice(Number(b.dataset.taxDelete),1);draw();};});}
    draw();m.querySelector("[data-tax-add]").onclick=function(){sync();entries.push({original:null,name:"새 분류"});draw();var inputs=list.querySelectorAll("[data-tax-name]"),last=inputs[inputs.length-1];if(last){last.focus();last.select();}};m.querySelector("[data-tax-reset]").onclick=function(){entries=baseRoomProductTaxonomy(r).map(function(t){return{original:t,name:t};});draw();};m.querySelector("[data-close]").onclick=function(){closeModal(m);};m.querySelector("[data-save]").onclick=function(){sync();var clean=[],seen={};entries.forEach(function(e){e.name=String(e.name||"").trim();if(!e.name||seen[e.name])return;seen[e.name]=1;clean.push(e);});clean=clean.slice(0,12);clean.forEach(function(e){if(!e.original||e.original===e.name)return;r.products.forEach(function(p){if(p.tags.indexOf(e.original)<0)return;p.tags=p.tags.map(function(t){return t===e.original?e.name:t;});markManualField(p,"tags");p.updatedAt=now();});});r.customTaxonomy=clean.map(function(e){return e.name;});productFilters=productFilters.filter(function(t){return r.customTaxonomy.indexOf(t)>=0;});touch(r);closeModal(m);renderRoom();host.toast("분류 태그를 저장했어요");};
  }

  function setupFeaturedLineEditor(m,id,limit){var input=m.querySelector("#"+id);if(!input)return;var helper=document.createElement("div");helper.className="st-feature-editor";input.insertAdjacentElement("afterend",helper);function values(){return String(input.value||"").split("\n").map(function(x){return x.trim();}).filter(Boolean);}function commit(list){input.value=list.join("\n");draw();}function draw(){var list=values();helper.innerHTML='<div class="st-feature-head"><b>대표 노출 '+Math.min(limit,list.length)+'개</b><span>나머지 '+Math.max(0,list.length-limit)+'개는 정보 보관함</span></div>'+(list.length?'<div class="st-feature-list">'+list.map(function(line,i){var featured=i<limit;return'<div class="st-feature-row '+(featured?'featured':'stored')+'"><span class="st-feature-rank">'+(featured?'대표 '+(i+1):'보관')+'</span><span class="st-feature-text">'+esc(line)+'</span><span class="st-feature-actions">'+(i>0?'<button type="button" data-feature-up="'+i+'" title="한 칸 위로">↑</button>':'')+(i<list.length-1?'<button type="button" data-feature-down="'+i+'" title="한 칸 아래로">↓</button>':'')+(!featured?'<button type="button" data-feature-promote="'+i+'">대표로</button>':'')+'</span></div>';}).join("")+'</div>':'<div class="st-note">아래 입력칸에 한 줄씩 추가하세요.</div>');helper.querySelectorAll("[data-feature-up],[data-feature-down],[data-feature-promote]").forEach(function(b){b.onclick=function(){var next=values(),from=Number(b.dataset.featureUp!=null?b.dataset.featureUp:b.dataset.featureDown!=null?b.dataset.featureDown:b.dataset.featurePromote),to=b.dataset.featureUp!=null?from-1:b.dataset.featureDown!=null?from+1:0,item=next.splice(from,1)[0];next.splice(to,0,item);commit(next);};});}input.addEventListener("input",draw);draw();}

  function productEditModal(r,p,isNew){function val(x){return esc(arr(x).join("\n"));}var m=modal('<h3>'+(isNew?'제품 직접 추가':'제품 정리 수정')+'</h3><div class="st-form"><div class="st-form-row"><label><span class="st-label">브랜드</span><input class="st-input" id="peBrand" value="'+esc(p.brand)+'"></label><label><span class="st-label">공식 제품명</span><input class="st-input" id="peName" value="'+esc(isNew?'':p.name)+'" placeholder="공식 제품명을 입력하세요"></label></div><label><span class="st-label">태그 4~6개 · 쉼표 구분</span><input class="st-input" id="peTags" value="'+esc(isNew?'':p.tags.join(", "))+'"></label><label><span class="st-label">핵심 포인트 · 무제한 보관 / 위 3개 노출</span><textarea class="st-textarea" id="pePoints">'+(isNew?'':val(p.points))+'</textarea></label><div class="st-form-row"><label><span class="st-label">추천 이유 · 무제한 보관 / 위 2개 노출</span><textarea class="st-textarea" id="pePro">'+(isNew?'':val(p.pro))+'</textarea></label><label><span class="st-label">비추천 이유 · 무제한 보관 / 위 2개 노출</span><textarea class="st-textarea" id="peCon">'+(isNew?'':val(p.con))+'</textarea></label></div><div class="st-form-row"><label><span class="st-label">추천 타깃 · 무제한 보관 / 위 2개 노출</span><textarea class="st-textarea" id="peTarget">'+(isNew?'':val(p.target))+'</textarea></label><label><span class="st-label">활용법·꿀팁 · 무제한 보관 / 위 2개 노출</span><textarea class="st-textarea" id="peTips">'+(isNew?'':val(p.tips))+'</textarea></label></div><label><span class="st-label">일화 · 무제한 보관 / 위 2개 노출</span><textarea class="st-textarea" id="peAnecdotes">'+(isNew?'':val(p.anecdotes))+'</textarea></label><label><span class="st-label">충돌</span><textarea class="st-textarea" id="peConflict">'+(isNew?'':esc(p.conflict))+'</textarea></label><div class="st-form-row"><label><span class="st-label">출처 추천도</span><input class="st-input" type="number" min="0" max="100" id="peSourceScore" value="'+(isNew?'0':esc(p.sourceScore))+'"></label><label><span class="st-label">샘터 적합도</span><input class="st-input" type="number" min="0" max="100" id="peFitScore" value="'+(isNew?'0':esc(p.fitScore))+'"></label></div><label><span class="st-label">최종 추천도</span><input class="st-input" type="number" min="0" max="100" id="peScore" value="'+(isNew?'0':esc(p.score))+'"></label></div><div class="st-modal-actions"><button class="st-btn" data-close>취소</button><button class="st-btn primary" data-save>'+(isNew?'제품 추가':'저장')+'</button></div>',true);[["pePoints",3],["pePro",2],["peCon",2],["peTarget",2],["peTips",2],["peAnecdotes",2]].forEach(function(x){setupFeaturedLineEditor(m,x[0],x[1]);});m.querySelector("[data-close]").onclick=function(){closeModal(m);};m.querySelector("[data-save]").onclick=function(){var entered=m.querySelector("#peName").value.trim();if(!entered){host.toast("공식 제품명을 입력해주세요");return;}p.brand=m.querySelector("#peBrand").value.trim();p.name=entered;p.tags=tagList(m.querySelector("#peTags").value.split(","));var pts=m.querySelector("#pePoints").value.split("\n").map(function(x){return x.trim();}).filter(Boolean);while(pts.length<3)pts.push("추가 핵심 확인 중");p.points=pts;p.pro=lineList(m.querySelector("#pePro").value);p.con=lineList(m.querySelector("#peCon").value);p.target=lineList(m.querySelector("#peTarget").value);p.tips=lineList(m.querySelector("#peTips").value);p.anecdotes=lineList(m.querySelector("#peAnecdotes").value,"추가 일화 확인 중");p.conflict=m.querySelector("#peConflict").value.trim();p.sourceScore=Math.max(0,Math.min(100,Number(m.querySelector("#peSourceScore").value)||0));p.fitScore=Math.max(0,Math.min(100,Number(m.querySelector("#peFitScore").value)||0));p.score=Math.max(0,Math.min(100,Number(m.querySelector("#peScore").value)||0));markAllManualFields(p);p.pendingAI=null;p.changeType="same";p.updatedAt=now();if(isNew)r.products.unshift(p);touch(r);closeModal(m);renderRoom();host.toast(isNew?"제품 정리에 추가했어요":"대표 노출과 보관 내용을 저장했어요");};}

