  function candidateProductsModal(r,c){var m=modal('<h3>구성 제품 선택</h3><p class="st-modal-desc">체크한 제품만 후보에 남습니다.</p>'+(r.products.length?'<div class="st-product-pick-list">'+r.products.map(function(p){var old=c.items.filter(function(it){return it.name===p.name&&it.selected!==false;})[0];return'<label class="st-product-pick"><input type="checkbox" data-pick-product="'+esc(p.id)+'" '+(old?'checked':'')+'><span><b>'+esc(p.name)+'</b><small>'+esc(p.brand)+' · 추천도 '+esc(p.score)+'</small></span></label>';}).join("")+'</div>':'<div class="st-note">제품 정리에 등록된 제품이 아직 없어요.</div>')+'<div class="st-modal-actions"><button class="st-btn" data-close>취소</button><button class="st-btn primary" data-save>선택 저장</button></div>');m.querySelector("[data-close]").onclick=function(){closeModal(m);};m.querySelector("[data-save]").onclick=function(){m.querySelectorAll("[data-pick-product]").forEach(function(ch){var p=r.products.filter(function(x){return x.id===ch.dataset.pickProduct;})[0];if(!p)return;var old=c.items.filter(function(it){return it.name===p.name;})[0];if(old&&!ch.checked)c.items=c.items.filter(function(it){return it.id!==old.id;});else if(!old&&ch.checked)c.items.push({id:uid(),name:p.name,text:p.points.join(" · "),tags:p.tags.slice(),sourceIds:unique(p.sourceIds),selected:true});});c.manualEdited=true;c.updatedAt=now();touch(r);closeModal(m);renderRoom();host.toast("체크한 제품만 후보에 남겼어요");};}

