  function resizeImage(file,cb){var fr=new FileReader();fr.onload=function(){var im=new Image();im.onload=function(){var mx=900,w=im.width,h=im.height;if(w>mx){h=Math.round(h*mx/w);w=mx;}var c=document.createElement("canvas");c.width=w;c.height=h;c.getContext("2d").drawImage(im,0,0,w,h);cb(c.toDataURL("image/jpeg",.7));};im.src=fr.result;};fr.readAsDataURL(file);}
