  function similarScore(a,b){a=cleanText(a);b=cleanText(b);if(!a||!b)return 0;var A={},B={},hit=0,total=0,i;for(i=0;i<a.length-2;i++)A[a.slice(i,i+3)]=1;for(i=0;i<b.length-2;i++)B[b.slice(i,i+3)]=1;Object.keys(A).forEach(function(k){if(B[k])hit++;});total=Object.keys(A).length+Object.keys(B).length-hit;return total?hit/total:0;}
